    // Variable to track if operation reported a change
    bool changeDetected = false;

    // Perform atomic operation that adds delta to the value
    changeDetected = resource.atomicOperation([&](int& currentValue) -> bool {
        // Add delta to current value
        currentValue += delta;

        // Return true if the value actually changed (delta != 0)
        return delta != 0;
    });

    // Get the final value
    int finalValue = resource.get();

    // Return the result
    return ResourceAtomicResult{finalValue, changeDetected};
}

